@startuml
title **ShoppingCart**

skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #e8f0e8
  BorderColor #888888
}

class ShoppingCart <<entity>> {
  /SubTotal : Currency
  /TaxAmount : Currency
  /DiscountAmount : Currency
  /TotalAmount : Currency
}

class ProductOnCart <<entity>> {
  /Price : Currency
  Quantity : Integer
  /Total : Currency
}

class Customer <<C>> {
}

class Product <<C>> {
}

ProductOnCart "0..*" --> "1..1" ShoppingCart : ShoppingCart
ShoppingCart "0..*" --> "0..*" ProductOnCart : ProductsOnCart
ShoppingCart "0..*" --> "1..1" Customer : Customer
ProductOnCart "0..*" --> "1..1" Product : Product

@enduml
